    queue<pair<long long, long long>> q;

    // 1. Initialize sources
    for (const auto& source : sources) {
        long long r = source[0];
        long long c = source[1];
        int color = static_cast<int>(source[2]);

        // Initial distance is 0
        grid_state[r][c] = {0, color};
        q.push({r, c});
    }

    // Directions: Up, Down, Left, Right
    int dr[] = {-1, 1, 0, 0};
    int dc[] = {0, 0, -1, 1};

    // 2. Multi-source BFS
