                // 1. If the new path is strictly shorter: Update and push to queue.
                if (next_dist < existing_dist) {
                    grid_state[nr][nc] = {next_dist, next_color};
                    q.push({nr, nc});
                } 
                // 2. If the new path is equally short: Choose the cell with the maximum color.
                else if (next_dist == existing_dist) {
                    if (next_color > existing_color) {
                        // Update color, but DO NOT re-queue. 
                        // Once a cell is reached at distance D, all cells reached at D 
                        // are processed together in the layer structure of the BFS.
                        // Changing the color at distance D does not change its distance, 
                        // so it won't lead to a new layer of expansion.
                        grid_state[nr][nc].second = next_color;
                        // We don't push to queue here because the neighbors of (nr, nc)
                        // would have already been processed based on the *old* color 
                        // if we were strictly layer-by-layer, but since we only push
                        // when the distance *strictly improves*, we are safe.
                        // If the color increases, the expansion from (nr, nc) 
                        // effectively happens in the same time step (D+1), 
                        // so pushing it again is redundant/risky for BFS structure.
                        // Since the problem implies simultaneous update, this color change 
                        // at distance D should only affect the final result, not the pathfinding itself.
                    }
                }
                // 3. If the new path is longer: Do nothing.
            }
        }
    }

    // 3. Construct the final result grid
    vector<vector<long long>> result(n, vector<long long>(m));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            // grid_state[i][j].second holds the winning color (or 0 if unreachable, which shouldn't happen given the problem constraints imply reachability if sources exist).
            result[i][j] = grid_state[i][j].second;
        }
    }

    return result;
