using namespace std;

/**
 * @brief Solves the color diffusion problem on a grid.
 * 
 * This problem is essentially a multi-source shortest path problem on a grid, 
 * where the "distance" is the time it takes for a color to reach a cell. 
 * Since we prioritize the color with the maximum value in case of a tie in arrival time, 
 * a variation of Dijkstra's algorithm or a multi-source BFS is suitable.
 * 
 * We use a priority queue to process cells in increasing order of arrival time (distance).
 * The state in the priority queue will be (time, color, r, c).
 * Since we want to maximize the color for a given time, we structure the priority queue 
 * to prioritize lower time first, and then higher color (to handle the max color rule implicitly 
 * or explicitly).
 * 
 * A simpler approach for this specific problem (where time is the primary factor and color is the tie-breaker):
 * 1. Use a 2D array `grid[N][M]` to store the final color, initialized to 0.
 * 2. Use a 2D array `dist[N][M]` to store the minimum time to reach a cell, initialized to infinity.
 * 3. Use a Priority Queue for Dijkstra's, ordered by (time, -color, r, c). Using -color ensures 
 *    that for the same time, the one with the larger color comes first.
 */
vector<vector<long long>> solve(long long n, long long m, vector<vector<long long>> sources) {
    // Grid dimensions are up to 10^5, but N*M <= 10^5. We must use dynamic sizing or check constraints carefully.
    // Since N, M are long long, we cast to int/size_t for array indexing assuming N*M constraint holds for practical memory usage.
    // Given N*M <= 10^5, using vector<vector<...>> of size N x M is fine.
    int N = (int)n;
    int M = (int)m;

    // grid[r][c] stores the final color, 0 if uncolored.
    vector<vector<long long>> grid(N, vector<long long>(M, 0));

    // dist[r][c] stores the minimum time (distance) to reach (r, c). Initialize to a large value.
    const long long INF = 1e18; 
    vector<vector<long long>> dist(N, vector<long long>(M, INF));

    // Priority Queue: Stores {time, -color, r, c}. 
    // We use negative color because C++ std::priority_queue is a max-heap, and we want to prioritize 
    // smaller time (min-heap behavior) and larger color (max-heap behavior on -color).
    // The tuple comparison will prioritize: 1. smallest time, 2. smallest -color (i.e., largest color).
    using State = tuple<long long, long long, int, int>;
    priority_queue<State, vector<State>, greater<State>> pq;

    // Initialize sources
    for (const auto& source : sources) {
        int r = (int)source[0];
        int c = (int)source[1];
        long long color = source[2];

        // Set initial state for sources
        grid[r][c] = color;
        dist[r][c] = 0;
        // Push {time=0, -color, r, c}
